-- =============================================
-- MedLens Database - قاعدة بيانات الأدوية
-- =============================================

CREATE DATABASE IF NOT EXISTS medlens CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE medlens;

CREATE TABLE IF NOT EXISTS drugs (
    id INT AUTO_INCREMENT PRIMARY KEY,
    product_id VARCHAR(20),
    drug_name_ar VARCHAR(200) NOT NULL,
    drug_name_en VARCHAR(200) NOT NULL,
    category_ar VARCHAR(100),
    category_en VARCHAR(100),
    form VARCHAR(50),
    active_ingredient VARCHAR(300),
    indications_ar TEXT,
    indications_en TEXT,
    side_effects_ar TEXT,
    side_effects_en TEXT,
    contraindications_ar TEXT,
    contraindications_en TEXT,
    storage_ar VARCHAR(200),
    storage_en VARCHAR(200),
    alternatives VARCHAR(300),
    model_class VARCHAR(100),
    INDEX idx_name_en (drug_name_en),
    INDEX idx_name_ar (drug_name_ar),
    INDEX idx_model (model_class),
    INDEX idx_category_en (category_en)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE IF NOT EXISTS users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    username VARCHAR(100) UNIQUE NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    role ENUM('user','admin') DEFAULT 'user',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

